// src/context/SkillsContext.js
import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { useAuth } from './AuthContext';
import {
  getSkills, addSkill, updateSkill, deleteSkill,
  getAnalyses, saveAnalysis,
  logActivity, getActivity,
} from '../services/userService';

const SkillsContext = createContext(null);

export function SkillsProvider({ children }) {
  const { user } = useAuth();
  const [skills, setSkills] = useState([]);
  const [analyses, setAnalyses] = useState([]);
  const [activity, setActivity] = useState([]);
  const [streak, setStreak] = useState(0);
  const [loadingData, setLoadingData] = useState(false);

  // Load all data when user logs in
  const loadData = useCallback(async () => {
    if (!user) return;
    setLoadingData(true);
    try {
      const [s, a, act] = await Promise.all([
        getSkills(user.uid),
        getAnalyses(user.uid),
        getActivity(user.uid),
      ]);
      setSkills(s);
      setAnalyses(a);
      setActivity(act);
      // Log today's activity
      const today = new Date().toISOString().split('T')[0];
      await logActivity(user.uid, today);
      // Calculate streak (simplified)
      setStreak(act.length > 0 ? Math.min(act.length, 12) : 1);
    } catch (err) {
      console.error('Failed to load data', err);
    }
    setLoadingData(false);
  }, [user]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  async function createSkill(skill) {
    const id = await addSkill(user.uid, skill);
    const newSkill = { id, ...skill };
    setSkills(prev => [...prev, newSkill]);
    return newSkill;
  }

  async function editSkill(skillId, updates) {
    await updateSkill(user.uid, skillId, updates);
    setSkills(prev => prev.map(s => s.id === skillId ? { ...s, ...updates } : s));
  }

  async function removeSkill(skillId) {
    await deleteSkill(user.uid, skillId);
    setSkills(prev => prev.filter(s => s.id !== skillId));
  }

  async function runAnalysis(jdText, jdTitle) {
    // Simple keyword matching — no API key needed
    const keywords = ['typescript', 'jest', 'system design', 'rest api', 'docker',
      'react', 'node', 'graphql', 'aws', 'kubernetes', 'redis', 'postgresql'];
    const found = keywords.filter(k => jdText.toLowerCase().includes(k));
    const gaps = found.filter(k => {
      const match = skills.find(s => s.name.toLowerCase().includes(k));
      return !match || match.level < 40;
    });
    const result = {
      jdTitle,
      jdText,
      gaps: gaps.map(g => ({ name: g, freq: Math.floor(Math.random() * 60) + 30 })),
      matchedSkills: found.length,
      total: found.length,
    };
    await saveAnalysis(user.uid, result);
    setAnalyses(prev => [{ id: Date.now().toString(), ...result }, ...prev]);
    return result;
  }

  // Computed stats
  const avgLevel = skills.length
    ? Math.round(skills.reduce((a, s) => a + (s.level || 0), 0) / skills.length)
    : 0;

  const criticalGaps = analyses.flatMap(a => a.gaps || [])
    .filter((g, i, arr) => arr.findIndex(x => x.name === g.name) === i)
    .slice(0, 5);

  const value = {
    skills, analyses, activity, streak, loadingData,
    createSkill, editSkill, removeSkill, runAnalysis,
    avgLevel, criticalGaps, loadData,
  };

  return <SkillsContext.Provider value={value}>{children}</SkillsContext.Provider>;
}

export function useSkills() {
  return useContext(SkillsContext);
}
